import SwiftUI

private let kOpenWeatherMapAPIKey = "768a1b47b3bfd8f5e94ed1a4f3630e48"
private let kCacheInterval: TimeInterval = 30 * 60

struct OWMResponse: Codable {
    let name: String?
    let main: Main?
    let weather: [WeatherItem]?
    struct Main: Codable {
        let temp: Double?
        let humidity: Int?
        let feels_like: Double?
    }
    struct WeatherItem: Codable {
        let main: String?
        let description: String?
    }
}

@MainActor
class WeatherViewModel: ObservableObject {
    @Published var cityName: String = ""
    @Published var temp: Double?
    @Published var condition: String?
    @Published var isLoading = false
    @Published var errorMessage: String?

    private var lastFetchTime: Date?
    private var cachedCity: String?

    func fetchWeather(city: String) {
        let trimmed = city.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }
        if let cached = cachedCity, cached == trimmed, let time = lastFetchTime, Date().timeIntervalSince(time) < kCacheInterval {
            isLoading = false
            errorMessage = nil
            return
        }
        isLoading = true
        errorMessage = nil
        let encoded = trimmed.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? trimmed
        guard let url = URL(string: "https://api.openweathermap.org/data/2.5/weather?q=\(encoded)&appid=\(kOpenWeatherMapAPIKey)&units=imperial") else {
            errorMessage = "Invalid city"
            isLoading = false
            return
        }
        Task {
            do {
                let (data, response) = try await URLSession.shared.data(from: url)
                guard let http = response as? HTTPURLResponse else {
                    errorMessage = "Invalid response"
                    isLoading = false
                    return
                }
                guard (200...299).contains(http.statusCode) else {
                    errorMessage = "Weather unavailable (HTTP \(http.statusCode))"
                    isLoading = false
                    return
                }
                let decoder = JSONDecoder()
                let owm = try decoder.decode(OWMResponse.self, from: data)
                lastFetchTime = Date()
                cachedCity = trimmed
                cityName = owm.name ?? trimmed
                temp = owm.main?.temp
                condition = owm.weather?.first?.description
                errorMessage = nil
            } catch {
                errorMessage = error.localizedDescription
            }
            isLoading = false
        }
    }
}

struct WeatherView: View {
    @StateObject private var viewModel = WeatherViewModel()
    @State private var cityInput = "San Francisco"

    var body: some View {
        VStack(spacing: 12) {
            TextField("City", text: $cityInput)
                .textFieldStyle(.roundedBorder)
                .padding(.horizontal)
            Button("Get weather") { viewModel.fetchWeather(city: cityInput) }
            Group {
                if viewModel.isLoading {
                    ProgressView("Loading…")
                } else if let message = viewModel.errorMessage {
                    Text(message)
                        .foregroundStyle(.red)
                } else if let temp = viewModel.temp {
                    VStack(spacing: 8) {
                        Text("\(viewModel.cityName)")
                            .font(.headline)
                        Text("\(Int(temp))°F")
                            .font(.largeTitle)
                        if let cond = viewModel.condition {
                            Text(cond)
                                .font(.subheadline)
                        }
                    }
                }
            }
        }
        .padding()
        .onAppear { viewModel.fetchWeather(city: cityInput) }
    }
}
